INSERT INTO questions_temps (id, category_question_id, front, back, p1, p2, p3, p4, answer, percentage, count, type, isfree, created_at, updated_at) VALUES ('1001', '217', '<div class="fullWidth">
                                                        <p ng-bind-html="q.QuestionText | unsafe" class="ng-binding"></p><div><div><span class="rz-text">ترجمه کدام گزینه </span><u><span class="rz-text">نادرست</span></u><span class="rz-text"> است؟</span></div></div>
                                                    </div>', '<div class="QuestionContent p-r-15 rtl ng-hide" ng-show="q.ShowStyle==2 &amp;&amp; q.CurrentImage=='a' &amp;&amp; q.CString==''" aria-hidden="true">
                                            <p ng-bind-html="q.AnswerText | unsafe" class="ng-binding"></p><div><div><span class="az-text">گزینه ۴‏ پاسخ صحیح است. </span><span class="az-text">«</span><span class="az-text">‌آیا تو، </span><u><span class="az-text">نیز</span></u><span class="az-text"> معنای کلمات کتاب اوّل را </span><u><span class="az-text">می</span><span>‌</span><span class="az-text">دانی</span></u><span class="az-text">؟</span><span class="az-text">»</span></div><div><span class="az-text">                                        أیضاً                                 تَعرِفُ</span></div></div>
                                        </div>', '<div id="2341022_view_1">
                                                            <p ng-bind-html="q.Choice1 | unsafe" class="ng-binding"></p><div><span class="cz-text"> إنَّ اللُّغَةَ</span><span class="cz-text"> الْعَرَبیَّةَ</span><span class="cz-text"> مِنَ اللُّغَاتِ الْعَالَمیَّةِ</span><span class="cz-text">: همانا زبان عربی از زبان</span><span>‌</span><span class="cz-text">های جهانی است.</span></div>
                                                        </div>', '<div id="2341022_view_2">
                                                            <p ng-bind-html="q.Choice2 | unsafe" class="ng-binding"></p><div><span class="cz-text"> أعْلَمُ النّاسِ مَنْ جَمَعَ عِلمَ النّاسِ إلی عِلمِهِ: داناترین مردم کسی است که علم مردم را به علمش بیافزاید.</span></div>
                                                        </div>', '<div id="2341022_view_3">
                                                            <p ng-bind-html="q.Choice3 | unsafe" class="ng-binding"></p><div><span class="cz-text"> أنَا أَعْرِفُ مَعنَی کَلِماتٍ کَثیرَةٍ</span><span class="cz-text">: من معنی کلمات زیادی را می</span><span>‌</span><span class="cz-text">دانم.</span></div>
                                                        </div>', '<div id="2341022_view_4">
                                                            <p ng-bind-html="q.Choice4 | unsafe" class="ng-binding"></p><div><span class="cz-text"> أَ أَنتَ تَعرِفُ مَعنَی کَلِماتِ الْکِتابِ الأَوَّلِ أَیْضَاً؟: ‌آیا تو می</span><span>‌</span><span class="cz-text">توانی کلمات کتاب اول را معنی کنی؟</span></div>
                                                        </div>', '4', '20', '100', 'test', '0', '2025-03-21 10:56:47', '2025-03-21 10:56:47');
INSERT INTO questions_temps (id, category_question_id, front, back, p1, p2, p3, p4, answer, percentage, count, type, isfree, created_at, updated_at) VALUES ('1002', '197', '<div class="fullWidth">
                                                        <p ng-bind-html="q.QuestionText | unsafe" class="ng-binding"></p><div><div><span class="rz-text">ترجمه</span><span>‌</span><span class="rz-text">ی کدام</span><span>‌</span><span class="rz-text">یک از عبارت</span><span>‌</span><span class="rz-text">های زیر </span><u><span class="rz-text">نادرست</span></u><span class="rz-text"> است؟</span></div></div>
                                                    </div>', '<div class="QuestionContent p-r-15 rtl ng-hide" ng-show="q.ShowStyle==2 &amp;&amp; q.CurrentImage=='a' &amp;&amp; q.CString==''" aria-hidden="true">
                                            <p ng-bind-html="q.AnswerText | unsafe" class="ng-binding"></p><div><div><span class="az-text">گزینه ۳‏ پاسخ صحیح است. </span><span class="az-text">«</span><span class="az-text">مُراجَعَ</span><span class="az-text">ة»</span><span class="az-text"> به معنی </span><span class="az-text">«</span><span class="az-text">مرور، دوره</span><span>‌</span><span class="az-text">کردن</span><span class="az-text">»</span><span class="az-text"> است که به اشتباه به صورت </span><span class="az-text">«</span><span class="az-text">خواندن</span><span class="az-text">»</span><span class="az-text"> ترجمه شده </span><span class="az-text">است. [‏</span><span class="az-text">«</span><span class="az-text">قراءَ</span><span>‌</span><span class="az-text">ة»</span><span class="az-text"> یعنی </span><span class="az-text">«</span><span class="az-text">خواندن</span><span class="az-text">»</span><span class="az-text">]‏</span></div></div>
                                        </div>', '<div id="2346647_view_1">
                                                            <p ng-bind-html="q.Choice1 | unsafe" class="ng-binding"></p><div><span class="cz-text"> أولئکَ الأمّهاتُ جالِساتٌ!: ‌آن مادران، نشسته</span><span>‌</span><span class="cz-text">اند!</span></div>
                                                        </div>', '<div id="2346647_view_2">
                                                            <p ng-bind-html="q.Choice2 | unsafe" class="ng-binding"></p><div><span class="cz-text"> هذا البَیتُ الکَبیرُ لِبروین اعتصامي</span><span class="cz-text">!: این خانه</span><span>‌</span><span class="cz-text">ی بزرگ، مال پروین اعتصامی است!</span></div>
                                                        </div>', '<div id="2346647_view_3">
                                                            <p ng-bind-html="q.Choice3 | unsafe" class="ng-binding"></p><div><span class="cz-text"> مُراجَعَةُ</span><span class="cz-text"> الدّرسِ الثّامِن ضَروريُّ</span><span class="cz-text">!: خواندن درس هشتم ضروری است!</span></div>
                                                        </div>', '<div id="2346647_view_4">
                                                            <p ng-bind-html="q.Choice4 | unsafe" class="ng-binding"></p><div><span class="cz-text"> مَعنی کَلمات هذا الدّرس بَسیطٌ!: معنای واژگان این درس، ساده است!</span></div>
                                                        </div>', '3', '20', '100', 'test', '0', '2025-03-21 10:56:47', '2025-03-21 10:56:47');
INSERT INTO questions_temps (id, category_question_id, front, back, p1, p2, p3, p4, answer, percentage, count, type, isfree, created_at, updated_at) VALUES ('1003', '217', '<div class="fullWidth">
                                                        <p ng-bind-html="q.QuestionText | unsafe" class="ng-binding"></p><div><div><span class="rz-text">ترجمه</span><span>‌</span><span class="rz-text">ی کدام</span><span>‌</span><span class="rz-text">یک از عبارت</span><span>‌</span><span class="rz-text">های زیر </span><u><span class="rz-text">نادرست نیست</span></u><span>؟</span></div></div>
                                                    </div>', '<div class="QuestionContent p-r-15 rtl ng-hide" ng-show="q.ShowStyle==2 &amp;&amp; q.CurrentImage=='a' &amp;&amp; q.CString==''" aria-hidden="true">
                                            <p ng-bind-html="q.AnswerText | unsafe" class="ng-binding"></p><div><div><span class="az-text">گزینه ۴‏ پاسخ صحیح است. بررسی سایر گزینه</span><span>‌</span><span class="az-text">ها:</span></div><div><span class="az-text">۱‏) </span><span class="az-text">«</span><span class="az-text">سَبعَ</span><span class="az-text">ة»</span><span class="az-text"> یعنی </span><span class="az-text">«</span><span class="az-text">هفت</span><span class="az-text">»</span><span class="az-text"> [‏</span><span class="az-text">«</span><span class="az-text">تِسعَ</span><span class="az-text">ة»</span><span class="az-text"> یعنی </span><span class="az-text">«</span><span class="az-text">نه</span><span class="az-text">»</span><span class="az-text">]‏</span></div><div><span class="az-text">۲‏) </span><span class="az-text">«</span><span class="az-text">هذان المُمَرِّضانِ</span><span class="az-text">»</span><span class="az-text"> یعنی </span><span class="az-text">«</span><span class="az-text">این پرستاران، این دو پرستار</span><span class="az-text">»</span><span class="az-text"> [‏</span><span class="az-text">«</span><span class="az-text">هذانِ المَریضانِ</span><span class="az-text">»</span><span class="az-text"> یعنی </span><span class="az-text">«</span><span class="az-text">این بیماران، این دو بیمار</span><span class="az-text">»</span><span class="az-text">]‏</span></div><div><span class="az-text">۳‏) </span><span class="az-text">«</span><span class="az-text">الشُّرط</span><span class="az-text">يّ»</span><span class="az-text"> یعنی </span><span class="az-text">«</span><span class="az-text">پلیس</span><span class="az-text">»</span><span class="az-text"> [‏</span><span class="az-text">«</span><span class="az-text">المُوَظَّف</span><span class="az-text">»</span><span class="az-text"> یعنی </span><span class="az-text">«</span><span class="az-text">کارمند</span><span class="az-text">»</span><span class="az-text">]‏</span></div></div>
                                        </div>', '<div id="2348968_view_1">
                                                            <p ng-bind-html="q.Choice1 | unsafe" class="ng-binding"></p><div><span class="cz-text"> عددُ کلماتِ مُعجَم الدّرس الأوّل سَبعَة</span><span class="cz-text"> کَلماتٍ!: تعداد کلمات واژه</span><span>‌</span><span class="cz-text">نامه</span><span>‌</span><span class="cz-text">ی درس اوّل نه کلمه است!</span></div>
                                                        </div>', '<div id="2348968_view_2">
                                                            <p ng-bind-html="q.Choice2 | unsafe" class="ng-binding"></p><div><span class="cz-text"> ذَهَبَ هذانِ المُمَرِّضانِ إلی بَیتِهما!: این دو بیمار به خانه</span><span>‌</span><span class="cz-text">هایشان رفتند!</span></div>
                                                        </div>', '<div id="2348968_view_3">
                                                            <p ng-bind-html="q.Choice3 | unsafe" class="ng-binding"></p><div><span class="cz-text"> هذا الشُّرطيُّ</span><span class="cz-text"> النّاجِحُ إیرانيﱣ</span><span class="cz-text">!: این کارمند موفّق، ایرانی است!</span></div>
                                                        </div>', '<div id="2348968_view_4">
                                                            <p ng-bind-html="q.Choice4 | unsafe" class="ng-binding"></p><div><span class="cz-text"> ذَهَبتُ مع أبي</span><span class="cz-text"> مَوقفِ الحافِلَة</span><span class="cz-text">!: با پدرم به ایستگاه اتوبوس رفتم!</span></div>
                                                        </div>', '4', '20', '100', 'test', '0', '2025-03-21 10:56:47', '2025-03-21 10:56:47');
INSERT INTO questions_temps (id, category_question_id, front, back, p1, p2, p3, p4, answer, percentage, count, type, isfree, created_at, updated_at) VALUES ('1004', '209', '<div class="fullWidth">
                                                        <p ng-bind-html="q.QuestionText | unsafe" class="ng-binding"></p><div><div><span class="rz-text">کدام کلمه از لحاظ دستوری با بقیه </span><u><span class="rz-text">ناهماهنگ</span></u><span class="rz-text"> است؟</span></div></div>
