INSERT INTO questions_temps (id, category_question_id, front, back, p1, p2, p3, p4, answer, percentage, count, type, isfree, created_at, updated_at) VALUES ('1005', '198', '<div class="fullWidth">
                                                        <p ng-bind-html="q.QuestionText | unsafe" class="ng-binding"></p><div><div><span class="rz-text">کدام گزینه پاسخ مناسبی برای سؤال </span><span>«</span><span class="rz-text">لِمَن هذَا البَیتُ؟</span><span>»</span><span class="rz-text"> است؟</span></div></div>
                                                    </div>', '<div class="QuestionContent p-r-15 rtl ng-hide" ng-show="q.ShowStyle==2 &amp;&amp; q.CurrentImage=='a' &amp;&amp; q.CString==''" aria-hidden="true">
                                            <p ng-bind-html="q.AnswerText | unsafe" class="ng-binding"></p><div><div><span class="az-text">گزینه ۲‏ پاسخ صحیح است. معنی عبارت سؤال: </span><span class="az-text">«</span><span class="az-text">این خانه، مالِ کیست؟ (این خانه</span><span>‌</span><span class="az-text">ی کیست؟)</span><span class="az-text">»</span></div><div><span class="az-text">ترجمه گزینه</span><span>‌</span><span class="az-text">ها:</span></div><div><span class="az-text">۱‏) این، خانه</span><span>‌</span><span class="az-text">ی بزرگی است.</span><span>                        </span><span>                        </span><span class="az-text">۲‏) این، خانه</span><span>‌</span><span class="az-text">ی سعید است.</span></div><div><span class="az-text">۳‏) بله، این خانه است.</span><span>                        </span><span>                        </span><span class="az-text">۴‏) نه، این مدرسه است.</span></div><div><span class="az-text">واضح است که گزینه</span><span>‌</span><span class="az-text">ی (۲‏) برای پاسخ به سؤال مطرح</span><span>‌</span><span class="az-text">شده صحیح است.</span></div></div>
                                        </div>', '<div id="2352382_view_1">
                                                            <p ng-bind-html="q.Choice1 | unsafe" class="ng-binding"></p><div><span class="cz-text"> هذا بیتٌ کبیرٌ!</span></div>
                                                        </div>', '<div id="2352382_view_2">
                                                            <p ng-bind-html="q.Choice2 | unsafe" class="ng-binding"></p><div><span class="cz-text"> هذا بیتُ سعیدٍ!</span></div>
                                                        </div>', '<div id="2352382_view_3">
                                                            <p ng-bind-html="q.Choice3 | unsafe" class="ng-binding"></p><div><span class="cz-text"> نعم، هذا بیتٌ!</span></div>
                                                        </div>', '<div id="2352382_view_4">
                                                            <p ng-bind-html="q.Choice4 | unsafe" class="ng-binding"></p><div><span class="cz-text"> لا، هذا مدرسةٌ</span><span>!</span></div>
                                                        </div>', '2', '20', '100', 'test', '0', '2025-03-21 10:56:47', '2025-03-21 10:56:47');
INSERT INTO questions_temps (id, category_question_id, front, back, p1, p2, p3, p4, answer, percentage, count, type, isfree, created_at, updated_at) VALUES ('1006', '210', '<div class="fullWidth">
