                                                        </div>', '2', '40', '100', 'test', '0', '2025-03-21 10:56:47', '2025-03-21 10:56:47');
INSERT INTO questions_temps (id, category_question_id, front, back, p1, p2, p3, p4, answer, percentage, count, type, isfree, created_at, updated_at) VALUES ('1007', '203', '<div class="fullWidth">
                                                        <p ng-bind-html="q.QuestionText | unsafe" class="ng-binding"></p><div><div><span class="rz-text">مفرد کدام</span><span>‌</span><span class="rz-text">یک از کلمات زیر مؤنّث است؟</span></div></div>
                                                    </div>', '<div class="QuestionContent p-r-15 rtl ng-hide" ng-show="q.ShowStyle==2 &amp;&amp; q.CurrentImage=='a' &amp;&amp; q.CString==''" aria-hidden="true">
