INSERT INTO questions_temps (id, category_question_id, front, back, p1, p2, p3, p4, answer, percentage, count, type, isfree, created_at, updated_at) VALUES ('1008', '198', '<div class="fullWidth">
                                                        <p ng-bind-html="q.QuestionText | unsafe" class="ng-binding"></p><div><div><span class="rz-text">پرسش و پاسخ کدام گزینه درست است؟</span></div></div>
                                                    </div>', '<div class="QuestionContent p-r-15 rtl ng-hide" ng-show="q.ShowStyle==2 &amp;&amp; q.CurrentImage=='a' &amp;&amp; q.CString==''" aria-hidden="true">
                                            <p ng-bind-html="q.AnswerText | unsafe" class="ng-binding"></p><div><div><span class="az-text">گزینه ۳‏ پاسخ صحیح است. بررسی گزینه</span><span>‌</span><span class="az-text">های نادرست:</span></div><div><span class="az-text">۱‏) چند روز در هفته وجود دارد؟ نه روز. [‏</span><span class="az-text">«</span><span class="az-text">سَبعَ</span><span class="az-text">ة</span><span class="az-text"> أیّام: هفت روز</span><span class="az-text">»</span><span class="az-text"> صحیح است.]‏</span></div><div><span class="az-text">۲‏) ‌آیا مادرت در سفر است؟ نه، او در خانه است. [‏به جای ضمیر </span><span class="az-text">«</span><span class="az-text">هو</span><span class="az-text">»</span><span class="az-text"> باید ضمیر </span><span class="az-text">«</span><span class="az-text">ه</span><span class="az-text">ي»</span><span class="az-text"> می</span><span>‌</span><span class="az-text">‌آمد، زیرا </span><span class="az-text">«</span><span class="az-text">أمّک: مادرت</span><span class="az-text">»</span><span class="az-text"> </span><span class="az-text">مؤنّث است.]‏</span></div><div><span class="az-text">۴‏) این دختر کیست؟ او دانش</span><span>‌</span><span class="az-text">‌آموز موفّقی است. [‏در پاسخ باید </span><span class="az-text">«</span><span class="az-text">ه</span><span class="az-text">ي</span><span class="az-text"> طالِبَ</span><span class="az-text">ةٌ</span><span class="az-text"> ناجِحَ</span><span class="az-text">ةٌ»</span><span class="az-text"> می</span><span>‌</span><span class="az-text">‌آمد، زیرا </span><span class="az-text">«</span><span class="az-text">هذِه البنت</span><span class="az-text">»</span><span class="az-text"> مفرد </span><span class="az-text">مؤنّث است.]‏</span></div></div>
                                        </div>', '<div id="2351544_view_1">
                                                            <p ng-bind-html="q.Choice1 | unsafe" class="ng-binding"></p><div><span class="cz-text"> کَم یَوماً في</span><span class="cz-text"> الأُسبُوعِِ؟ تِسعَة</span><span class="cz-text"> أیّامٍ.</span></div>
                                                        </div>', '<div id="2351544_view_2">
                                                            <p ng-bind-html="q.Choice2 | unsafe" class="ng-binding"></p><div><span class="cz-text"> هَل أُمُّک في</span><span class="cz-text"> السَّفَرِ؟ لا، هُوَ في</span><span class="cz-text"> البَیتِ.</span></div>
                                                        </div>', '<div id="2351544_view_3">
                                                            <p ng-bind-html="q.Choice3 | unsafe" class="ng-binding"></p><div><span class="cz-text"> أینَ جَلَسَ أبُوکَ؟ هو جَلَسَ أمامَ البابِ.</span></div>
                                                        </div>', '<div id="2351544_view_4">
                                                            <p ng-bind-html="q.Choice4 | unsafe" class="ng-binding"></p><div><span class="cz-text"> مَن هذِه البِنتُ؟ هُوَ طالِبٌ ناجِحٌ.</span></div>
                                                        </div>', '3', '40', '100', 'test', '0', '2025-03-21 10:56:47', '2025-03-21 10:56:47');
INSERT INTO questions_temps (id, category_question_id, front, back, p1, p2, p3, p4, answer, percentage, count, type, isfree, created_at, updated_at) VALUES ('1009', '205', '<div class="fullWidth">
                                                        <p ng-bind-html="q.QuestionText | unsafe" class="ng-binding"></p><div><div><span class="rz-text">کاربرد اسم اشاره در کدام گزینه صحیح است؟</span></div></div>
                                                    </div>', '<div class="QuestionContent p-r-15 rtl ng-hide" ng-show="q.ShowStyle==2 &amp;&amp; q.CurrentImage=='a' &amp;&amp; q.CString==''" aria-hidden="true">
                                            <p ng-bind-html="q.AnswerText | unsafe" class="ng-binding"></p><div><div><span class="az-text">گزینه ۴‏ پاسخ صحیح است. </span><span class="az-text">«</span><span class="az-text">أولئک الأطفال</span><span class="az-text">»</span><span class="az-text"> صحیح است، زیرا </span><span class="az-text">«</span><span class="az-text">الأطفال</span><span class="az-text">»</span><span class="az-text"> جمع انسان است و برای جمع انسان نیز از </span><span class="az-text">اسم</span><span>‌</span><span class="az-text">های اشاره</span><span>‌</span><span class="az-text">ی </span><span class="az-text">«</span><span class="az-text">أولئک</span><span class="az-text">»</span><span class="az-text"> و </span><span class="az-text">«</span><span class="az-text">هؤلاء</span><span class="az-text">»</span><span class="az-text"> استفاده می</span><span>‌</span><span class="az-text">شود. بررسی گزینه</span><span>‌</span><span class="az-text">های نادرست:</span></div><div><span class="az-text">۱‏) </span><span class="az-text">«</span><span class="az-text">ذلِک المَدین</span><span class="az-text">ة»</span><span class="az-text"> نادرست است و صحیح ‌آن </span><span class="az-text">«</span><span class="az-text">تِلکَ المَدین</span><span class="az-text">ة»</span><span class="az-text"> می</span><span>‌</span><span class="az-text">باشد، زیرا </span><span class="az-text">«</span><span class="az-text">المَدین</span><span class="az-text">ة»</span><span class="az-text"> مفرد مؤنّث است. [‏</span><span class="az-text">«</span><span class="az-text">هذا الشَّخصُ</span><span class="az-text">»</span><span class="az-text"> </span><span class="az-text">صحیح است.]‏</span></div><div><span class="az-text">۲‏) </span><span class="az-text">«</span><span class="az-text">هذه الطَّعام</span><span class="az-text">»</span><span class="az-text"> نادرست است و صحیح ‌آن </span><span class="az-text">«</span><span class="az-text">هذا الطّعام</span><span class="az-text">»</span><span class="az-text"> است، زیرا </span><span class="az-text">«</span><span class="az-text">الطّعام</span><span class="az-text">»</span><span class="az-text"> مفرد مذکّر است در حالی که </span><span class="az-text">«</span><span class="az-text">هذِه</span><span class="az-text">»</span><span class="az-text"> اسم </span><span class="az-text">اشاره برای مفرد مؤنّث است. [‏</span><span class="az-text">«</span><span class="az-text">هذا الحَلوان</span><span class="az-text">يّ»</span><span class="az-text"> صحیح است.]‏</span></div><div><span class="az-text">۳‏) </span><span class="az-text">«</span><span class="az-text">هذانِ الشّاعِرتانِ</span><span class="az-text">»</span><span class="az-text"> نادرست است و صحیح ‌آن </span><span class="az-text">«</span><span class="az-text">هاتانِ الشّاعِرتانِ</span><span class="az-text">»</span><span class="az-text"> است، زیرا </span><span class="az-text">«</span><span class="az-text">الشّاعِرتانِ</span><span class="az-text">»</span><span class="az-text"> مثنّی مؤنّث است، در حالی </span><span class="az-text">که </span><span class="az-text">«</span><span class="az-text">هذانِ</span><span class="az-text">»</span><span class="az-text"> اسم اشاره برای مثنّی مذکّر است.</span></div></div>
                                        </div>', '<div id="2354036_view_1">
                                                            <p ng-bind-html="q.Choice1 | unsafe" class="ng-binding"></p><div><span class="cz-text"> هذا الشَّخصُ طَبیبٌ في</span><span class="cz-text"> ذلِک المَدینةِ</span><span>!</span></div>
                                                        </div>', '<div id="2354036_view_2">
                                                            <p ng-bind-html="q.Choice2 | unsafe" class="ng-binding"></p><div><span class="cz-text"> هذا الحَلوانيُّ</span><span class="cz-text"> ماهِرٌ في</span><span class="cz-text"> طَبخِ هذِه الطّعام!</span></div>
                                                        </div>', '<div id="2354036_view_3">
                                                            <p ng-bind-html="q.Choice3 | unsafe" class="ng-binding"></p><div><span class="cz-text"> هذانِ الشّاعِرتانِ، مَشهُورتانِ کثیراً!</span></div>
                                                        </div>', '<div id="2354036_view_4">
                                                            <p ng-bind-html="q.Choice4 | unsafe" class="ng-binding"></p><div><span class="cz-text"> أولئکَ الأطفالُ مَسرُورونَ عندَ والِدیهِم!</span></div>
                                                        </div>', '4', '40', '100', 'test', '0', '2025-03-21 10:56:47', '2025-03-21 10:56:47');
INSERT INTO questions_temps (id, category_question_id, front, back, p1, p2, p3, p4, answer, percentage, count, type, isfree, created_at, updated_at) VALUES ('1010', '202', '<div class="fullWidth">
                                                        <p ng-bind-html="q.QuestionText | unsafe" class="ng-binding"></p><div><div><span class="rz-text">کدام گزینه برای جاهای خالی مناسب است؟ </span><span>«</span><span class="rz-text">....... قبلَ تِسعَة</span><span class="rz-text"> و ....... بعدَ سَبعَة</span><span>.</span><span>»</span></div></div>
                                                    </div>', '<div class="QuestionContent p-r-15 rtl ng-hide" ng-show="q.ShowStyle==2 &amp;&amp; q.CurrentImage=='a' &amp;&amp; q.CString==''" aria-hidden="true">
                                            <p ng-bind-html="q.AnswerText | unsafe" class="ng-binding"></p><div><div><span class="az-text">گزینه ۱‏ پاسخ صحیح است. قبل از </span><span class="az-text">«</span><span class="az-text">تِسعَ</span><span class="az-text">ة</span><span class="az-text"> (نُه)</span><span class="az-text">»</span><span class="az-text">، عدد </span><span class="az-text">«</span><span class="az-text">ثَمانِی</span><span class="az-text">ة</span><span class="az-text"> (هشت)</span><span class="az-text">»</span><span class="az-text">، و بعد از </span><span class="az-text">«</span><span class="az-text">سَبعَ</span><span class="az-text">ة</span><span class="az-text"> (هفت)</span><span class="az-text">»</span><span class="az-text"> نیز عدد </span><span class="az-text">«</span><span class="az-text">ثَمانِیَ</span><span class="az-text">ة</span><span class="az-text"> </span><span class="az-text">(هشت)</span><span class="az-text">»</span><span class="az-text"> قرار دارد.</span></div></div>
                                        </div>', '<div id="2346849_view_1">
                                                            <p ng-bind-html="q.Choice1 | unsafe" class="ng-binding"></p><div><span class="cz-text"> ثَمانِیة</span><span class="cz-text"> - ثَمانِیة</span></div>
                                                        </div>', '<div id="2346849_view_2">
                                                            <p ng-bind-html="q.Choice2 | unsafe" class="ng-binding"></p><div><span class="cz-text"> سِتَّة</span><span class="cz-text"> - ثَمانِیَة</span></div>
                                                        </div>', '<div id="2346849_view_3">
                                                            <p ng-bind-html="q.Choice3 | unsafe" class="ng-binding"></p><div><span class="cz-text"> ثَمانِیَة</span><span class="cz-text"> - عَشَرة</span></div>
                                                        </div>', '<div id="2346849_view_4">
                                                            <p ng-bind-html="q.Choice4 | unsafe" class="ng-binding"></p><div><span class="cz-text"> سِتَّة</span><span class="cz-text"> - عَشَرة</span></div>
                                                        </div>', '1', '60', '100', 'test', '0', '2025-03-21 10:56:47', '2025-03-21 10:56:47');
INSERT INTO questions_temps (id, category_question_id, front, back, p1, p2, p3, p4, answer, percentage, count, type, isfree, created_at, updated_at) VALUES ('1011', '197', '<div class="fullWidth">
                                                        <p ng-bind-html="q.QuestionText | unsafe" class="ng-binding"></p><div><div><span class="rz-text">ترجمه</span><span>‌</span><span class="rz-text">ی اسم اشاره در کدام گزینه متفاوت است؟</span></div></div>
                                                    </div>', '<div class="QuestionContent p-r-15 rtl ng-hide" ng-show="q.ShowStyle==2 &amp;&amp; q.CurrentImage=='a' &amp;&amp; q.CString==''" aria-hidden="true">
                                            <p ng-bind-html="q.AnswerText | unsafe" class="ng-binding"></p><div><div><span class="az-text">گزینه ۲‏ پاسخ صحیح است. اگر بعد از </span><span class="az-text">«</span><span class="az-text">هؤلاء/ اولئک</span><span class="az-text">»</span><span class="az-text"> اسم دارای </span><span class="az-text">«</span><span class="az-text">ال</span><span class="az-text">ـ»</span><span class="az-text"> و جمع بیاید، به صورت مفرد ترجمه می</span><span>‌</span><span class="az-text">شود </span><span class="az-text">ولی در گزینه</span><span>‌</span><span class="az-text">های دیگر چون بعد از </span><span class="az-text">«</span><span class="az-text">هؤلاء/ اولئک</span><span class="az-text">»</span><span class="az-text"> اسم بدون </span><span class="az-text">«</span><span class="az-text">ال</span><span class="az-text">ـ»</span><span class="az-text"> یا غیرمرتبط به اسم اشاره [‏مثل گزینهٔ ۱‏]‏ ‌آمده است، </span><span class="az-text">پس به صورت جمع ترجمه می</span><span>‌</span><span class="az-text">شود!</span></div><div><span class="az-text">ترجمه گزینه</span><span>‌</span><span class="az-text">ها:</span></div><div><span class="az-text">۱‏) اینان، برنج را در خانه پختند.</span><span>                        </span><span class="az-text">۲‏) این دانش</span><span>‌</span><span class="az-text">‌آموزان کنارِ دَر ایستاده</span><span>‌</span><span class="az-text">اند.</span></div><div><span class="az-text">۳‏) ‌آنان، بازیکنان ممتازی هستند.</span><span>                        </span><span class="az-text">۴‏) ‌آنان، دانش</span><span>‌</span><span class="az-text">‌آموزان صبوری هستند.</span></div></div>
                                        </div>', '<div id="2351164_view_1">
                                                            <p ng-bind-html="q.Choice1 | unsafe" class="ng-binding"></p><div><span class="cz-text"> طَبَخَت هؤلاءِ، الرُّزَّ في</span><span class="cz-text"> البَیتِ! </span></div>
                                                        </div>', '<div id="2351164_view_2">
                                                            <p ng-bind-html="q.Choice2 | unsafe" class="ng-binding"></p><div><span class="cz-text"> هؤلاءِ الطّالبونَ واقِفونَ عِندَ البابِ!</span></div>
                                                        </div>', '<div id="2351164_view_3">
                                                            <p ng-bind-html="q.Choice3 | unsafe" class="ng-binding"></p><div><span class="cz-text"> أولئکَ لاعِبونَ مُمتازونَ!</span><span>                        </span></div>
                                                        </div>', '<div id="2351164_view_4">
                                                            <p ng-bind-html="q.Choice4 | unsafe" class="ng-binding"></p><div><span class="cz-text"> أولئکَ زَمیلاتٌ صابِراتٌ!</span></div>
                                                        </div>', '2', '40', '100', 'test', '0', '2025-03-21 10:56:47', '2025-03-21 10:56:47');
INSERT INTO questions_temps (id, category_question_id, front, back, p1, p2, p3, p4, answer, percentage, count, type, isfree, created_at, updated_at) VALUES ('1012', '202', '<div class="fullWidth">
                                                        <p ng-bind-html="q.QuestionText | unsafe" class="ng-binding"></p><div><div><span class="rz-text">کدام</span><span>‌</span><span class="rz-text">یک از کلمات زیر از نظر معنایی یا دستوری با سایر کلمات </span><u><span class="rz-text">ناهماهنگ</span></u><span class="rz-text"> است؟</span></div></div>
                                                    </div>', '<div class="QuestionContent p-r-15 rtl ng-hide" ng-show="q.ShowStyle==2 &amp;&amp; q.CurrentImage=='a' &amp;&amp; q.CString==''" aria-hidden="true">
                                            <p ng-bind-html="q.AnswerText | unsafe" class="ng-binding"></p><div><div><span class="az-text">گزینه</span><span>‌</span><span class="az-text"> ۱‏ پاسخ صحیح است. </span><span class="az-text">«</span><span class="az-text">فَعَلنَ</span><span class="az-text">»</span><span class="az-text"> فعل ماضی مناسب با صیغه</span><span>‌</span><span class="az-text">ی </span><span class="az-text">«</span><span class="az-text">هُنَّ</span><span class="az-text">»</span><span class="az-text"> است، امّا سایر کلمات همگی اسم هستند.</span></div></div>
                                        </div>', '<div id="2347992_view_1">
                                                            <p ng-bind-html="q.Choice1 | unsafe" class="ng-binding"></p><div><span class="cz-text"> فَعَلنَ</span></div>
                                                        </div>', '<div id="2347992_view_2">
                                                            <p ng-bind-html="q.Choice2 | unsafe" class="ng-binding"></p><div><span class="cz-text"> فاعِلینَ</span></div>
                                                        </div>', '<div id="2347992_view_3">
                                                            <p ng-bind-html="q.Choice3 | unsafe" class="ng-binding"></p><div><span class="cz-text"> فاعِلَة</span></div>
                                                        </div>', '<div id="2347992_view_4">
                                                            <p ng-bind-html="q.Choice4 | unsafe" class="ng-binding"></p><div><span class="cz-text"> رَجُلانِ</span></div>
                                                        </div>', '1', '40', '100', 'test', '0', '2025-03-21 10:56:47', '2025-03-21 10:56:47');
INSERT INTO questions_temps (id, category_question_id, front, back, p1, p2, p3, p4, answer, percentage, count, type, isfree, created_at, updated_at) VALUES ('1013', '197', '<div class="fullWidth">
                                                        <p ng-bind-html="q.QuestionText | unsafe" class="ng-binding"></p><div><div><span class="rz-text">ترجمه</span><span>‌</span><span class="rz-text">ی کدام</span><span>‌</span><span class="rz-text">یک از عبارت</span><span>‌</span><span class="rz-text">های زیر </span><u><span class="rz-text">نادرست</span></u><span class="rz-text"> است؟</span></div></div>
                                                    </div>', '<div class="QuestionContent p-r-15 rtl ng-hide" ng-show="q.ShowStyle==2 &amp;&amp; q.CurrentImage=='a' &amp;&amp; q.CString==''" aria-hidden="true">
                                            <p ng-bind-html="q.AnswerText | unsafe" class="ng-binding"></p><div><div><span class="az-text">گزینه</span><span>‌</span><span class="az-text"> ۳‏ پاسخ صحیح است. </span><span class="az-text">«</span><span class="az-text">رُبَّ</span><span class="az-text">»</span><span class="az-text"> به معنی </span><span class="az-text">«</span><span class="az-text">چه بسا</span><span class="az-text">»</span><span class="az-text"> است که به اشتباه به صورت </span><span class="az-text">«</span><span class="az-text">چه بسیار</span><span class="az-text">»</span><span class="az-text"> ترجمه شده است.</span></div></div>
                                        </div>', '<div id="2354410_view_1">
                                                            <p ng-bind-html="q.Choice1 | unsafe" class="ng-binding"></p><div><span class="cz-text"> حَدائِقُ هذِه المَدینةِ</span><span class="cz-text"> کبیرةٌ</span><span class="cz-text"> و جَمیلةٌ</span><span class="cz-text">: باغ</span><span>‌</span><span class="cz-text">های این شهر، بزرگ و زیبا هستند.</span></div>
                                                        </div>', '<div id="2354410_view_2">
                                                            <p ng-bind-html="q.Choice2 | unsafe" class="ng-binding"></p><div><span class="cz-text"> رأیتُ صورةَ</span><span class="cz-text"> هذا الشّهیدِ علی جِدارِ الغُرفَةِ</span><span class="cz-text">: عکس این شهید را روی دیوار اتاق دیدم.</span></div>
                                                        </div>', '<div id="2354410_view_3">
                                                            <p ng-bind-html="q.Choice3 | unsafe" class="ng-binding"></p><div><span class="cz-text"> رُبَّ کَلامٍ جَوابُه السُّکوتُ: چه بسیار سخنی که پاسخ ‌آن سکوت است.</span></div>
                                                        </div>', '<div id="2354410_view_4">
                                                            <p ng-bind-html="q.Choice4 | unsafe" class="ng-binding"></p><div><span class="cz-text"> أسرتي</span><span class="cz-text"> جالِسونَ هُناکَ تَحتَ الشّجرةِ</span><span class="cz-text">: خانواده</span><span>‌</span><span class="cz-text">ام ‌آن</span><span>‌</span><span class="cz-text">جا زیر درخت نشسته</span><span>‌</span><span class="cz-text">اند.</span></div>
