INSERT INTO questions_temps (id, category_question_id, front, back, p1, p2, p3, p4, answer, percentage, count, type, isfree, created_at, updated_at) VALUES ('1020', '210', '<div class="fullWidth">
                                                        <p ng-bind-html="q.QuestionText | unsafe" class="ng-binding"></p><div><div><span class="rz-text">کدام گزینه به ترتیب برای تکمیل جاهای خالی عبارت زیر مناسب هستند؟</span></div><div><span>«</span><span>في</span><span class="rz-text"> کلّ فَصلٍ ....... شُهُورٍ، و في</span><span class="rz-text"> کلّ سَنَةٍ</span><span class="rz-text"> ....... شَهراً.</span><span>»</span></div></div>
                                                    </div>', '<div class="QuestionContent p-r-15 rtl ng-hide" ng-show="q.ShowStyle==2 &amp;&amp; q.CurrentImage=='a' &amp;&amp; q.CString==''" aria-hidden="true">
                                            <p ng-bind-html="q.AnswerText | unsafe" class="ng-binding"></p><div><div><span class="az-text">گزینه</span><span>‌</span><span class="az-text"> ۱‏ پاسخ صحیح است. معنی عبارت سؤال: </span><span class="az-text">«</span><span class="az-text">در هر فصل ....... ماه، و در هر سال ....... ماه وجود دارد.</span><span class="az-text">»</span><span class="az-text"> که به </span><span class="az-text">ترتیب عبارت است از: </span><span class="az-text">«</span><span class="az-text">ثَلاثَ</span><span class="az-text">ة</span><span class="az-text"> (سه)</span><span class="az-text">»</span><span class="az-text"> و </span><span class="az-text">«</span><span class="az-text">اِثنا عَشَرَ (دوازده)</span><span class="az-text">»</span><span class="az-text"> [‏</span><span class="az-text">«</span><span class="az-text">أربَعَ</span><span class="az-text">ة»</span><span class="az-text"> و </span><span class="az-text">«</span><span class="az-text">أحَدَ عَشَرَ</span><span class="az-text">»</span><span class="az-text"> به ترتیب به معنی </span><span class="az-text">«</span><span class="az-text">چهار</span><span class="az-text">»</span><span class="az-text"> و </span><span class="az-text">«</span><span class="az-text">یازده</span><span class="az-text">»</span><span class="az-text"> </span><span class="az-text">هستند.]‏</span></div></div>
                                        </div>', '<div id="2349210_view_1">
                                                            <p ng-bind-html="q.Choice1 | unsafe" class="ng-binding"></p><div><span class="cz-text"> ثَلاثَة</span><span class="cz-text"> - اِثنا عَشَرَ</span></div>
                                                        </div>', '<div id="2349210_view_2">
                                                            <p ng-bind-html="q.Choice2 | unsafe" class="ng-binding"></p><div><span class="cz-text"> أربَعَة</span><span class="cz-text"> - أحَدَ عَشَرَ</span></div>
                                                        </div>', '<div id="2349210_view_3">
                                                            <p ng-bind-html="q.Choice3 | unsafe" class="ng-binding"></p><div><span class="cz-text"> ثَلاثَة</span><span class="cz-text"> - أحَدَ عَشَرَ</span></div>
                                                        </div>', '<div id="2349210_view_4">
