                                                        </div>', '1', '40', '100', 'test', '0', '2025-03-21 10:56:47', '2025-03-21 10:56:47');
INSERT INTO questions_temps (id, category_question_id, front, back, p1, p2, p3, p4, answer, percentage, count, type, isfree, created_at, updated_at) VALUES ('1021', '329', '<div class="fullWidth">
                                                        <p ng-bind-html="q.QuestionText | unsafe" class="ng-binding"></p><div><div><span class="rz-text">کدام</span><span>‌</span><span class="rz-text">یک از گزینه</span><span>‌</span><span class="rz-text">های زیر </span><u><span class="rz-text">نادرست</span></u><span class="rz-text"> است؟</span></div></div>
                                                    </div>', '<div class="QuestionContent p-r-15 rtl ng-hide" ng-show="q.ShowStyle==2 &amp;&amp; q.CurrentImage=='a' &amp;&amp; q.CString==''" aria-hidden="true">
                                            <p ng-bind-html="q.AnswerText | unsafe" class="ng-binding"></p><div><div><span class="az-text">گزینه</span><span>‌</span><span class="az-text"> ۴‏ پاسخ صحیح است. </span><span class="az-text">«</span><span class="az-text">روز وسط از روزهای هفته، روز دوشنبه است.</span><span class="az-text">»</span><span class="az-text"> که نادرست است، زیرا روز وسط هفته </span><span class="az-text">«</span><span class="az-text">روز سه</span><span>‌</span><span class="az-text">شنبه (الثّلاثاء) است.</span><span class="az-text">»</span><span class="az-text"> ترجمه سایر گزینه</span><span>‌</span><span class="az-text">ها:</span></div><div><span class="az-text">۱‏) روز ‌آخر از روزهای هفته، روز جمعه است.</span></div><div><span class="az-text">۲‏) روز پنجم از روزهای هفته، روز چهارشنبه است.</span></div><div><span class="az-text">۳‏) روز اوّل از روزهای هفته، روز شنبه است.</span></div></div>
                                        </div>', '<div id="2349079_view_1">
                                                            <p ng-bind-html="q.Choice1 | unsafe" class="ng-binding"></p><div><span class="cz-text"> الیَومُ الاٰخِرُ مِن أیّامِ الأسبُو</span><span>عِ</span><span class="cz-text">، یَومُ الجُمُعة</span><span>.</span></div>
                                                        </div>', '<div id="2349079_view_2">
                                                            <p ng-bind-html="q.Choice2 | unsafe" class="ng-binding"></p><div><span class="cz-text"> الیَومُ الخامِسُ مِن أیّامِ الأسبُو</span><span>عِ</span><span class="cz-text">، یَومُ الأربِعاء.</span></div>
                                                        </div>', '<div id="2349079_view_3">
                                                            <p ng-bind-html="q.Choice3 | unsafe" class="ng-binding"></p><div><span class="cz-text"> الیَومُ الأوّلُ مِن أیّام الأسبُوع، یَومُ السَّبت.</span></div>
