                                                            <p ng-bind-html="q.Choice4 | unsafe" class="ng-binding"></p><div><span class="cz-text"> الیَومُ الوسطُ مِن أیّامِ الأسبُو</span><span>عِ</span><span class="cz-text">، یَومُ الإثنَین.</span></div>
                                                        </div>', '4', '40', '100', 'test', '0', '2025-03-21 10:56:47', '2025-03-21 10:56:47');
