INSERT INTO questions_temps (id, category_question_id, front, back, p1, p2, p3, p4, answer, percentage, count, type, isfree, created_at, updated_at) VALUES ('1038', '238', '<div class="fullWidth">
                                                        <p ng-bind-html="q.QuestionText | unsafe" class="ng-binding"></p><div><div><span class="rz-text">کدام گزینه از نظر قواعد درست است؟</span></div></div>
                                                    </div>', '<div class="QuestionContent p-r-15 rtl ng-hide" ng-show="q.ShowStyle==2 &amp;&amp; q.CurrentImage=='a' &amp;&amp; q.CString==''" aria-hidden="true">
                                            <p ng-bind-html="q.AnswerText | unsafe" class="ng-binding"></p><div><div><span class="az-text">گزینه ۴‏ پاسخ صحیح است. ۱‏) أنت .... تَطبَخُ / ۲‏) أنتِ شُرطیّ</span><span class="az-text">ة</span><span class="az-text"> تَحفَظینَ / ۳‏) أنا .... أصنَعُ</span></div></div>
