INSERT INTO questions_temps (id, category_question_id, front, back, p1, p2, p3, p4, answer, percentage, count, type, isfree, created_at, updated_at) VALUES ('1039', '207', '<div class="fullWidth">
                                                        <p ng-bind-html="q.QuestionText | unsafe" class="ng-binding"></p><div><div><span class="rz-text">کدام پرسش برای پاسخ (اَلفَرسُ یَحمِلُ الحَقیبَةَ</span><span class="rz-text">) درست </span><u><span class="rz-text">نیست</span></u><span>؟</span></div></div>
