                                            <p ng-bind-html="q.AnswerText | unsafe" class="ng-binding"></p><div><div><span class="az-text">گزینه ۲‏ پاسخ صحیح است.</span></div><div><span class="az-text">پرسش </span><span class="az-text">«</span><span class="az-text">اسب برای چه کسی بار حمل می</span><span>‌</span><span class="az-text">کند</span><span class="az-text">»</span><span class="az-text">، پاسخی در جملهٔ </span><span class="az-text">«</span><span class="az-text">اسب، کیف را حمل می</span><span>‌</span><span class="az-text">کند</span><span class="az-text">»</span><span class="az-text">، ندارد.</span></div></div>
                                        </div>', '<div id="2353819_view_1">
