INSERT INTO questions_temps (id, category_question_id, front, back, p1, p2, p3, p4, answer, percentage, count, type, isfree, created_at, updated_at) VALUES ('1044', '252', '<div class="fullWidth">
                                                        <p ng-bind-html="q.QuestionText | unsafe" class="ng-binding"></p><div><div><span class="rz-text">کدام گزینه با کلمه</span><span>‌</span><span class="rz-text">ی مقابلش کامل </span><u><span class="rz-text">نمی</span><span>‌</span><span class="rz-text">شود</span></u><span>؟</span></div></div>
                                                    </div>', '<div class="QuestionContent p-r-15 rtl ng-hide" ng-show="q.ShowStyle==2 &amp;&amp; q.CurrentImage=='a' &amp;&amp; q.CString==''" aria-hidden="true">
                                            <p ng-bind-html="q.AnswerText | unsafe" class="ng-binding"></p><div><div><span class="az-text">گزینه ۱‏ پاسخ صحیح است.</span></div><div><span class="az-text">«</span><span class="az-text">زینب</span><span class="az-text">»</span><span class="az-text"> اسم مفرد مؤنّث است پس فعل مضارع بعدش </span><span class="az-text">«</span><span class="az-text">تأت</span><span class="az-text">ي»</span><span class="az-text"> بصورت مفرد مؤنّث غائب صحیح است.</span></div></div>
