INSERT INTO questions_temps (id, category_question_id, front, back, p1, p2, p3, p4, answer, percentage, count, type, isfree, created_at, updated_at) VALUES ('1045', '217', '<div class="fullWidth">
                                                        <p ng-bind-html="q.QuestionText | unsafe" class="ng-binding"></p><div><div><span class="rz-text">کدام ترجمه </span><u><span class="rz-text">نادرست</span></u><span class="rz-text"> است؟</span></div></div>
                                                    </div>', '<div class="QuestionContent p-r-15 rtl ng-hide" ng-show="q.ShowStyle==2 &amp;&amp; q.CurrentImage=='a' &amp;&amp; q.CString==''" aria-hidden="true">
                                            <p ng-bind-html="q.AnswerText | unsafe" class="ng-binding"></p><div><div><span class="az-text">گزینه ۲‏ پاسخ صحیح است. </span><span class="az-text">«</span><span class="az-text">تو معنای احادیث ‌آسان را نیز می</span><span>‌</span><span class="az-text">فهمی</span><span class="az-text">»</span><span class="az-text"> ترجمهٔ صحیح گزینهٔ پاسخ است.</span></div></div>
