                                                        </div>', '<div id="1312900_view_3">
                                                            <p ng-bind-html="q.Choice3 | unsafe" class="ng-binding"></p><div class="cz-ltr "><span class="rz-entext">act</span></div>
                                                        </div>', '<div id="1312900_view_4">
                                                            <p ng-bind-html="q.Choice4 | unsafe" class="ng-binding"></p><div class="cz-ltr "><span class="rz-entext">recite</span></div>
                                                        </div>', '4', '20', '100', 'test', '0', '2025-03-21 10:56:54', '2025-03-21 10:56:54');
INSERT INTO questions_temps (id, category_question_id, front, back, p1, p2, p3, p4, answer, percentage, count, type, isfree, created_at, updated_at) VALUES ('1307', '359', '<div class="fullWidth">
