                                        </div>', '<div id="1312898_view_1">
                                                            <p ng-bind-html="q.Choice1 | unsafe" class="ng-binding"></p><div class="cz-ltr "><span class="rz-entext">can - do</span></div>
                                                        </div>', '<div id="1312898_view_2">
                                                            <p ng-bind-html="q.Choice2 | unsafe" class="ng-binding"></p><div class="cz-ltr "><span class="rz-entext">can't - fix</span></div>
                                                        </div>', '<div id="1312898_view_3">
                                                            <p ng-bind-html="q.Choice3 | unsafe" class="ng-binding"></p><div class="cz-ltr "><span class="rz-entext">can't - do</span></div>
                                                        </div>', '<div id="1312898_view_4">
                                                            <p ng-bind-html="q.Choice4 | unsafe" class="ng-binding"></p><div class="cz-ltr "><span class="rz-entext">can - fix</span></div>
                                                        </div>', '2', '60', '100', 'test', '0', '2025-03-21 10:56:55', '2025-03-21 10:56:55');
