                                            <p ng-bind-html="q.AnswerText | unsafe" class="ng-binding"></p><div><div><span class="az-text">گزینه ۳‏ پاسخ صحیح است. قبل از روزهای هفته حرف اضافهٔ ''n‏o‏'' به</span><span>‌</span><span class="az-text">کار می</span><span>‌</span><span class="az-text">رود. شکل صیح جملهٔ مورد نظر </span><span class="az-text">به</span><span>‌</span><span class="az-text">صورت زیر است:</span></div><div class="az-ltr "><span class="rz-entext">I stay at home </span><u><span class="rz-entext">on</span></u><span class="rz-entext"> </span><u><span class="rz-entext">Sunday mornings</span></u><span class="rz-entext">.</span></div></div>
                                        </div>', '<div id="1297527_view_1">
                                                            <p ng-bind-html="q.Choice1 | unsafe" class="ng-binding"></p><div class="cz-ltr "><span class="rz-entext">I stay at home in Sunday mornings.</span></div>
                                                        </div>', '<div id="1297527_view_2">
                                                            <p ng-bind-html="q.Choice2 | unsafe" class="ng-binding"></p><div class="cz-ltr "><span class="rz-entext">I stay at home on morning Sundays.</span></div>
                                                        </div>', '<div id="1297527_view_3">
                                                            <p ng-bind-html="q.Choice3 | unsafe" class="ng-binding"></p><div class="cz-ltr "><span class="rz-entext">I stay at home on Sunday mornings.</span></div>
                                                        </div>', '<div id="1297527_view_4">
                                                            <p ng-bind-html="q.Choice4 | unsafe" class="ng-binding"></p><div class="cz-ltr "><span class="rz-entext">I stay at home in morning Sundays.</span></div>
                                                        </div>', '3', '40', '100', 'test', '0', '2025-03-21 10:56:58', '2025-03-21 10:56:58');
