INSERT INTO questions_temps (id, category_question_id, front, back, p1, p2, p3, p4, answer, percentage, count, type, isfree, created_at, updated_at) VALUES ('1722', '361', '<div class="fullWidth">
                                                        <p ng-bind-html="q.QuestionText | unsafe" class="ng-binding"></p><div><div><span class="rz-text">کلمه</span><span>‌</span><span class="rz-text">های پرسشی مناسب برای سؤالات زیر در کدام گزینه به درستی ‌آمده است؟</span></div><div class="rz-ltr "><span class="rz-entext">A) ''.......... is good at cooking?</span><span class="rz-formula"><span class="MathJax_Preview" style="color: inherit;"></span><span id="MathJax-Element-7922-Frame" class="mjx-chtml MathJax_CHTML" tabindex="0" data-mathml='&lt;math xmlns="http://www.w3.org/1998/Math/MathML" display="inline" displaystyle="true"&gt;&lt;mstyle displaystyle="true" dir="ltr" /&gt;&lt;/math&gt;' style="position: relative;" role="presentation"><span id="MJXc-Node-59794" class="mjx-math" aria-hidden="true"><span id="MJXc-Node-59795" class="mjx-mrow"><span id="MJXc-Node-59796" class="mjx-mstyle"><span id="MJXc-Node-59797" class="mjx-mrow"></span></span></span></span><span class="MJX_Assistive_MathML" role="presentation"><math xmlns="http://www.w3.org/1998/Math/MathML" display="inline" displaystyle="true"><mstyle displaystyle="true" dir="ltr"></mstyle></math></span></span><script type="math/mml" id="MathJax-Element-7922"><math display="inline" displaystyle="true"><mstyle displaystyle="true" dir="ltr">   </script></span><span class="rz-entext">'' ''Maryam.''</span></div><div class="rz-ltr "><span class="rz-entext">B) ''.......... sports can you play?</span><span class="rz-formula"><span class="MathJax_Preview" style="color: inherit;"></span><span id="MathJax-Element-7923-Frame" class="mjx-chtml MathJax_CHTML" tabindex="0" data-mathml='&lt;math xmlns="http://www.w3.org/1998/Math/MathML" display="inline" displaystyle="true"&gt;&lt;mstyle displaystyle="true" dir="ltr" /&gt;&lt;/math&gt;' style="position: relative;" role="presentation"><span id="MJXc-Node-59798" class="mjx-math" aria-hidden="true"><span id="MJXc-Node-59799" class="mjx-mrow"><span id="MJXc-Node-59800" class="mjx-mstyle"><span id="MJXc-Node-59801" class="mjx-mrow"></span></span></span></span><span class="MJX_Assistive_MathML" role="presentation"><math xmlns="http://www.w3.org/1998/Math/MathML" display="inline" displaystyle="true"><mstyle displaystyle="true" dir="ltr"></mstyle></math></span></span><script type="math/mml" id="MathJax-Element-7923"><math display="inline" displaystyle="true"><mstyle displaystyle="true" dir="ltr">   </script></span><span class="rz-entext">'' ''</span><span class="rz-formula"><span class="MathJax_Preview" style="color: inherit;"></span><span id="MathJax-Element-7924-Frame" class="mjx-chtml MathJax_CHTML" tabindex="0" data-mathml='&lt;math xmlns="http://www.w3.org/1998/Math/MathML" display="inline" displaystyle="true"&gt;&lt;mstyle displaystyle="true" dir="ltr" /&gt;&lt;/math&gt;' style="position: relative;" role="presentation"><span id="MJXc-Node-59802" class="mjx-math" aria-hidden="true"><span id="MJXc-Node-59803" class="mjx-mrow"><span id="MJXc-Node-59804" class="mjx-mstyle"><span id="MJXc-Node-59805" class="mjx-mrow"></span></span></span></span><span class="MJX_Assistive_MathML" role="presentation"><math xmlns="http://www.w3.org/1998/Math/MathML" display="inline" displaystyle="true"><mstyle displaystyle="true" dir="ltr"></mstyle></math></span></span><script type="math/mml" id="MathJax-Element-7924"><math display="inline" displaystyle="true"><mstyle displaystyle="true" dir="ltr">   </script></span><span class="rz-entext">I can play football.''</span></div></div>
                                                    </div>', '<div class="QuestionContent p-r-15 rtl ng-hide" ng-show="q.ShowStyle==2 &amp;&amp; q.CurrentImage=='a' &amp;&amp; q.CString==''" aria-hidden="true">
                                            <p ng-bind-html="q.AnswerText | unsafe" class="ng-binding"></p><div><div><span class="az-text">گزینه ۲‏ پاسخ صحیح است. ترجمهٔ جمله</span><span>‌</span><span class="az-text">ها:</span></div><div><span class="az-text">A‏: </span><span class="az-text">«</span><u><span class="az-text">چه کسی</span></u><span class="az-text"> در ‌آشپزی خوب است؟</span><span class="az-text">»</span><span class="az-text"> </span><span class="az-text">«</span><span class="az-text">مریم.</span><span class="az-text">»</span></div><div><span class="az-text">B‏: </span><span class="az-text">«</span><u><span class="az-text">چه</span></u><span class="az-text"> ورزش</span><span>‌</span><span class="az-text">هایی می</span><span>‌</span><span class="az-text">توانید انجام دهید؟</span><span class="az-text">»</span><span class="az-text"> </span><span class="az-text">«</span><span class="az-text">می</span><span>‌</span><span class="az-text">توانم فوتبال بازی کنم.</span><span class="az-text">»</span></div><div><span class="az-text">۱‏) چرا - چه کسی</span><span>                        </span><span class="az-text">۲‏) چه کسی - چه، کدام</span><span>                        </span><span class="az-text">۳‏) چه</span><span>‌</span><span class="az-text">طور - چه کسی</span><span>                        </span><span class="az-text">۴‏) چرا - چه، کدام</span></div></div>
                                        </div>', '<div id="1297484_view_1">
