INSERT INTO questions_temps (id, category_question_id, front, back, p1, p2, p3, p4, answer, percentage, count, type, isfree, created_at, updated_at) VALUES ('1794', '388', '<div class="fullWidth">
                                                        <p ng-bind-html="q.QuestionText | unsafe" class="ng-binding"></p><div><div class="rz-ltr "><span class="rz-entext">Student 1: What do you and Ali do on Monday afternoons?</span></div><div class="rz-ltr "><span class="rz-entext">Student 2: ....... .</span></div></div>
