                                            <p ng-bind-html="q.AnswerText | unsafe" class="ng-binding"></p><div><div><span class="az-text">گزینه ۲‏ پاسخ صحیح است. معنی جمله</span><span>‌</span><span class="az-text">ها:</span></div><div><span class="az-text">دانش</span><span>‌</span><span class="az-text">‌آموز ۱‏: شما و علی بعدازظهرهای دوشنبه چه می</span><span>‌</span><span class="az-text">کنید؟</span></div><div><span class="az-text">دانش</span><span>‌</span><span class="az-text">‌آموز ۲‏: ما به باشگاه می</span><span>‌</span><span class="az-text">رویم.</span></div><div><span class="az-text">معنی گزینه</span><span>‌</span><span class="az-text">ها:</span></div><div><span class="az-text">۱‏) ‌آن</span><span>‌</span><span class="az-text">ها انگلیسی مطالعه می</span><span>‌</span><span class="az-text">کنند.</span><span>                        </span><span class="az-text">۲‏) ما به باشگاه می</span><span>‌</span><span class="az-text">رویم.</span></div><div><span class="az-text">۳‏) من ورزش می</span><span>‌</span><span class="az-text">کنم.</span><span>                        </span><span>                        </span><span class="az-text">۴‏) شما تلویزیون تماشا می</span><span>‌</span><span class="az-text">کنید.</span></div></div>
                                        </div>', '<div id="2342298_view_1">
                                                            <p ng-bind-html="q.Choice1 | unsafe" class="ng-binding"></p><div class="cz-ltr "><span class="rz-entext">They study Enghlish</span></div>
                                                        </div>', '<div id="2342298_view_2">
                                                            <p ng-bind-html="q.Choice2 | unsafe" class="ng-binding"></p><div class="cz-ltr "><span class="rz-entext">We go to the gym</span></div>
                                                        </div>', '<div id="2342298_view_3">
                                                            <p ng-bind-html="q.Choice3 | unsafe" class="ng-binding"></p><div class="cz-ltr "><span class="rz-entext">I play sports</span><span>                        </span></div>
                                                        </div>', '<div id="2342298_view_4">
                                                            <p ng-bind-html="q.Choice4 | unsafe" class="ng-binding"></p><div class="cz-ltr "><span class="rz-entext">You watch TV</span></div>
                                                        </div>', '2', '20', '100', 'test', '0', '2025-03-21 10:56:58', '2025-03-21 10:56:58');
INSERT INTO questions_temps (id, category_question_id, front, back, p1, p2, p3, p4, answer, percentage, count, type, isfree, created_at, updated_at) VALUES ('1795', '388', '<div class="fullWidth">
                                                        <p ng-bind-html="q.QuestionText | unsafe" class="ng-binding"></p><div><div class="rz-ltr "><span class="rz-entext">Amir: What do the students do during the week?</span></div><div class="rz-ltr "><span class="rz-entext">Majid: ....... .</span></div></div>
