INSERT INTO questions_temps (id, category_question_id, front, back, p1, p2, p3, p4, answer, percentage, count, type, isfree, created_at, updated_at) VALUES ('1796', '377', '<div class="fullWidth">
                                                        <p ng-bind-html="q.QuestionText | unsafe" class="ng-binding"></p><div><div class="rz-ltr "><span class="rz-entext">Amin: Are there many cities and villages in Japan?</span></div><div class="rz-ltr "><span class="rz-entext">Ahmad: Yes, ....... .</span></div></div>
