INSERT INTO questions_temps (id, category_question_id, front, back, p1, p2, p3, p4, answer, percentage, count, type, isfree, created_at, updated_at) VALUES ('1798', '400', '<div class="fullWidth">
                                                        <p ng-bind-html="q.QuestionText | unsafe" class="ng-binding"></p><div><div><span class="rz-text">کدام پرسش و پاسخ درست </span><u><span class="rz-text">نمی</span><span>‌</span><span class="rz-text">باشد</span></u><span>؟</span></div></div>
                                                    </div>', '<div class="QuestionContent p-r-15 rtl ng-hide" ng-show="q.ShowStyle==2 &amp;&amp; q.CurrentImage=='a' &amp;&amp; q.CString==''" aria-hidden="true">
                                            <p ng-bind-html="q.AnswerText | unsafe" class="ng-binding"></p><div><div><span class="az-text">گزینه ۳‏ پاسخ صحیح است. پرسش و پاسخ گزینه</span><span>‌</span><span class="az-text">ی (۳‏) درست </span><u><span class="az-text">نمی</span><span>‌</span><span class="az-text">باشد</span></u><span class="az-text">.</span></div><div><span class="az-text">معنی گزینه</span><span>‌</span><span class="az-text">ها:</span></div><div><span class="az-text">۱‏) الف) من ‌آنفولانزا گرفته</span><span>‌</span><span class="az-text">ام.</span><span>                        </span><span class="az-text">ب) چرا به پزشک مراجعه نمی</span><span>‌</span><span class="az-text">کنی؟</span></div><div><span class="az-text">۲‏) الف) جمعه عصر چطور؟</span><span>                        </span><span>                        </span><span class="az-text">ب) من خانه می</span><span>‌</span><span class="az-text">مانم و استراحت می</span><span>‌</span><span class="az-text">کنم.</span></div><div><span class="az-text">۳‏) الف) شیراز کجاست؟</span><span>                        </span><span>                        </span><span class="az-text">ب) ‌آن کشور زیبایی است.</span></div><div><span class="az-text">۴‏) الف) ‌آیا موزه</span><span>‌</span><span class="az-text">ای وجود دارد؟</span><span>                        </span><span class="az-text">ب) بله، چند موزه</span><span>‌</span><span class="az-text">ی عالی.</span></div></div>
                                        </div>', '<div id="2327296_view_1">
                                                            <p ng-bind-html="q.Choice1 | unsafe" class="ng-binding"></p><div class="cz-ltr "><span class="rz-entext">A: I have the flu.</span><span>                        </span><span>                        </span><span class="rz-entext">B: Why don't you see a doctor?</span></div>
                                                        </div>', '<div id="2327296_view_2">
                                                            <p ng-bind-html="q.Choice2 | unsafe" class="ng-binding"></p><div class="cz-ltr "><span class="rz-entext">A: How about Friday afternoon? </span><span>                        </span><span class="rz-entext">B: I stay at home and relax.</span></div>
                                                        </div>', '<div id="2327296_view_3">
                                                            <p ng-bind-html="q.Choice3 | unsafe" class="ng-binding"></p><div class="cz-ltr "><span class="rz-entext">A: Where is Shiraz?</span><span>                        </span><span class="rz-entext">B: It's a beautiful country.</span></div>
                                                        </div>', '<div id="2327296_view_4">
                                                            <p ng-bind-html="q.Choice4 | unsafe" class="ng-binding"></p><div class="cz-ltr "><span class="rz-entext">A: Are there any museum? </span><span>                        </span><span class="rz-entext">B: Yes, some great ones.</span></div>
                                                        </div>', '3', '60', '100', 'test', '0', '2025-03-21 10:56:59', '2025-03-21 10:56:59');
INSERT INTO questions_temps (id, category_question_id, front, back, p1, p2, p3, p4, answer, percentage, count, type, isfree, created_at, updated_at) VALUES ('1799', '348', '<div class="fullWidth">
                                                        <p ng-bind-html="q.QuestionText | unsafe" class="ng-binding"></p><div><div class="rz-ltr "><span class="rz-entext">Ali: Are you from France?</span></div><div class="rz-ltr "><span class="rz-entext">Amin: ...... .</span></div></div>
                                                    </div>', '<div class="QuestionContent p-r-15 rtl ng-hide" ng-show="q.ShowStyle==2 &amp;&amp; q.CurrentImage=='a' &amp;&amp; q.CString==''" aria-hidden="true">
                                            <p ng-bind-html="q.AnswerText | unsafe" class="ng-binding"></p><div><div><span class="az-text">گزینه ۳‏ پاسخ صحیح است. </span></div><div><span class="az-text">معنی جمله</span><span>‌</span><span class="az-text">ها:</span></div><div><span class="az-text">علی: ‌آیا شما اهل فرانسه هستید؟</span></div><div><span class="az-text">امین: بله، هستم.</span></div><div><span class="az-text">بررسی سایر گزینه</span><span>‌</span><span class="az-text">ها:</span></div><div><span class="az-text">۱‏) در پاسخ کوتاه، فعل با فاعل به صورت کوتاه</span><span>‌</span><span class="az-text">شده (مخفف) به کار نمی</span><span>‌</span><span class="az-text">رود.</span></div><div><span class="az-text">۲‏) در سؤال ضمیر </span><span class="az-formula"><span class="MathJax_Preview" style="color: inherit;"></span><span id="MathJax-Element-7981-Frame" class="mjx-chtml MathJax_CHTML" tabindex="0" data-mathml='&lt;math xmlns="http://www.w3.org/1998/Math/MathML" display="inline" displaystyle="true"&gt;&lt;mstyle displaystyle="true" dir="ltr"&gt;&lt;mi&gt;you&lt;/mi&gt;&lt;/mstyle&gt;&lt;/math&gt;' style="position: relative;" role="presentation"><span id="MJXc-Node-60125" class="mjx-math" aria-hidden="true"><span id="MJXc-Node-60126" class="mjx-mrow"><span id="MJXc-Node-60127" class="mjx-mstyle"><span id="MJXc-Node-60128" class="mjx-mrow"><span id="MJXc-Node-60129" class="mjx-mi"><span class="mjx-char MJXc-TeX-main-R" style="padding-top: 0.146em; padding-bottom: 0.575em;">you</span></span></span></span></span></span><span class="MJX_Assistive_MathML" role="presentation"><math xmlns="http://www.w3.org/1998/Math/MathML" display="inline" displaystyle="true"><mstyle displaystyle="true" dir="ltr"><mi>you</mi></mstyle></math></span></span><script type="math/mml" id="MathJax-Element-7981"><math display="inline" displaystyle="true"><mstyle displaystyle="true" dir="ltr"><mi>you</script></span><span class="az-text"> ‌آمده است، بنابراین در پاسخ باید از ضمیر </span><span cla