INSERT INTO questions_temps (id, category_question_id, front, back, p1, p2, p3, p4, answer, percentage, count, type, isfree, created_at, updated_at) VALUES ('1825', '400', '<div class="fullWidth">
                                                        <p ng-bind-html="q.QuestionText | unsafe" class="ng-binding"></p><div><div><span class="rz-text">جملات ناقص زیر را با کلمات داده شده کامل کنید.</span></div><div class="rz-ltr "><span class="rz-entext">Who - Italy - back - toothache - Iran</span></div><div class="rz-ltr "><span class="rz-entext">1 - Is She Iranian?</span><span>                        </span><span class="rz-entext">No, She is from .......</span></div><div class="rz-ltr "><span class="rz-entext">2- They will be ....... in a minute.</span></div><div class="rz-ltr "><span class="rz-entext">3- ....... is that woman standing over there?</span></div><div class="rz-ltr "><span class="rz-entext">4- I have a ....... I should go to the dentist.</span></div></div>
