INSERT INTO questions_temps (id, category_question_id, front, back, p1, p2, p3, p4, answer, percentage, count, type, isfree, created_at, updated_at) VALUES ('1826', '400', '<div class="fullWidth">
                                                        <p ng-bind-html="q.QuestionText | unsafe" class="ng-binding"></p><div><div><span class="rz-text">برای سؤالات سمت چپ پاسخ مناسبی از سمت راست بیایید. (در ستون سمت راست یک مورد اضافی است.)</span></div><div class="rz-ltr "><span class="rz-entext">1- What do you in the evenings? .......</span><span>                        </span><span class="rz-entext">a. Yes, my mother</span></div><div class="rz-ltr "><span class="rz-entext">2- What's the problem? .......</span><span>                        </span><span class="rz-entext">b. I can't make it.</span></div><div class="rz-ltr "><span class="rz-entext">3- How about Friday afternoon? .......</span><span>                        </span><span class="rz-entext">c. play football</span></div><div class="rz-ltr "><span class="rz-entext">4- Are you good at driving? .......</span><span>                        </span><span class="rz-entext">d. I have a backache</span></div><div class="rz-ltr "><span>                        </span><span>                        </span><span class="rz-entext">e. Yes, of course.</span></div></div>
                                                    </div>', '<div class="QuestionContent p-r-15 rtl ng-hide" ng-show="q.ShowStyle==2 &amp;&amp; q.CurrentImage=='a' &amp;&amp; q.CString==''" aria-hidden="true">
                                            <p ng-bind-html="q.AnswerText | unsafe" class="ng-binding"></p><div><div class="az-ltr "><span class="rz-entext">1- c</span><span>                        </span><span class="rz-entext">2- d</span><span>                        </span><span class="rz-entext">3- b</span><span>                        </span><span class="rz-entext">4- e</span></div></div>
                                        </div>', '', '', '', '', '', '20', '100', 'descriptive', '0', '2025-03-21 10:56:59', '2025-03-21 10:56:59');
