INSERT INTO questions_temps (id, category_question_id, front, back, p1, p2, p3, p4, answer, percentage, count, type, isfree, created_at, updated_at) VALUES ('1849', '372', '<div class="fullWidth">
                                                        <p ng-bind-html="q.QuestionText | unsafe" class="ng-binding"></p><div><div><span class="rz-text">با توجه به تصاویر، جاهای خالی زیر را با عبارات صحیح کامل کنید. (تکراری نباشد.)</span></div><div class="rz-ltr "><span class="rz-entext">        (1)</span><span>                        </span><span>                        </span><span class="rz-entext">         (2)</span></div><div class="rz-ltr "><span class="rz-entext">Smith has .......</span><span>                        </span><span>                        </span><span class="rz-entext">Tom has a r .......</span></div><div class="rz-ltr "><span class="rz-entext">your advice: .......</span><span>                        </span><span>                        </span><span class="rz-entext">your advice: .......</span></div><div class="rz-ltr "><span><img class="unique" src="/images/Questions/15/341/372/37528292-ebbe-4a0c-b22a-5e95bcd5c8a2.png"></span><span>                        </span><span>                        </span><span><img class="unique" src="/images/Questions/15/341/372/8d8f00bb-0818-4121-a8e8-851900859d0e.png"></span></div><div class="rz-ltr "><span class="rz-entext">-------------------------------------------------------------------------------------------------</span></div><div class="rz-ltr "><span class="rz-entext">        (3)</span><span>                        </span><span>                        </span><span class="rz-entext">                  (4)</span></div><div class="rz-ltr "><span class="rz-entext">Ronald has a .......</span><span>                        </span><span>                        </span><span class="rz-entext">He is good at ....... , but he can't</span></div><div class="rz-ltr "><span class="rz-entext">your advice: .......</span><span>                        </span><span>                        </span><span class="rz-entext">....................</span></div><div class="rz-ltr "><span><img class="unique" src="https://tx.quiz24.ir/1082673/042c9a71-5f87-4309-a778-446b75b73e0d.png"></span><span>                        </span><span>                        </span><span><img class="unique" src="https://tx.quiz24.ir/1082673/f8dc13e8-e046-48ce-ad25-b58f3c136492.png"></span></div></div>
                                                    </div>', '<div class="QuestionContent p-r-15 rtl ng-hide" ng-show="q.ShowStyle==2 &amp;&amp; q.CurrentImage=='a' &amp;&amp; q.CString==''" aria-hidden="true">
                                            <p ng-bind-html="q.AnswerText | unsafe" class="ng-binding"></p><div><div class="az-ltr "><span class="rz-entext">1) Earache / go home</span><span>                        </span><span>                        </span><span class="rz-entext">2) runing nose / rest</span></div><div class="az-ltr "><span class="rz-entext">3) toothach / dentist</span><span>                        </span><span>                        </span><span class="rz-entext">4) swimming / ride a horse </span></div></div>
                                        </div>', '', '', '', '', '', '20', '100', 'descriptive', '0', '2025-03-21 10:56:59', '2025-03-21 10:57:50');
INSERT INTO questions_temps (id, category_question_id, front, back, p1, p2, p3, p4, answer, percentage, count, type, isfree, created_at, updated_at) VALUES ('1850', '372', '<div class="fullWidth">
