INSERT INTO questions_temps (id, category_question_id, front, back, p1, p2, p3, p4, answer, percentage, count, type, isfree, created_at, updated_at) VALUES ('1863', '377', '<div class="fullWidth">
                                                        <p ng-bind-html="q.QuestionText | unsafe" class="ng-binding"></p><div><div class="rz-ltr "><span class="rz-entext">A: Are there many churches in your city?</span></div><div class="rz-ltr "><span class="rz-entext">B: No, there is only one downtown. But there are many mosques there. We understand </span><span class="rz-entext">that .......</span></div></div>
