INSERT INTO questions_temps (id, category_question_id, front, back, p1, p2, p3, p4, answer, percentage, count, type, isfree, created_at, updated_at) VALUES ('1959', '392', '<div class="fullWidth">
                                                        <p ng-bind-html="q.QuestionText | unsafe" class="ng-binding"></p><div><div><span class="rz-text">با توجه به تصویر، مکالمهٔ زیر را کامل کنید.</span></div><div class="rz-ltr "><span class="rz-entext">A: What do you do in your free time?</span></div><div class="rz-ltr "><span class="rz-entext">B: I .......... .</span></div><div class="rz-ltr "><div><span><img class="unique" src="/images/Questions/15/341/387/392/078d158c-e897-4762-b9aa-6b7672d6299b.png"></span></div></div></div>
                                                    </div>', '<div class="QuestionContent p-r-15 rtl ng-hide" ng-show="q.ShowStyle==2 &amp;&amp; q.CurrentImage=='a' &amp;&amp; q.CString==''" aria-hidden="true">
                                            <p ng-bind-html="q.AnswerText | unsafe" class="ng-binding"></p><div><div><span class="az-text">گزینه ۳‏ پاسخ صحیح است. ترجمهٔ جمله</span><span>‌</span><span class="az-text">ها:</span></div><div><span class="az-text">A‏: شما در اوقات فراغت خود چه کاری انجام می</span><span>‌</span><span class="az-text">دهید؟</span></div><div><span class="az-text">B‏: من اسب</span><span>‌</span><span class="az-text">سواری می</span><span>‌</span><span class="az-text">روم.</span></div><div><span class="az-text">۱‏) رفتن به خرید</span><span>                        </span><span>                        </span><span class="az-text">۲‏) بازی</span><span>‌</span><span class="az-text">های کامپیوتری بازی کردن</span></div><div><span class="az-text">۳‏) رفتن به اسب</span><span>‌</span><span class="az-text">سواری</span><span>                        </span><span>                        </span><span class="az-text">۴‏) قدم زدن در پارک</span></div></div>
                                        </div>', '<div id="2291896_view_1">
                                                            <p ng-bind-html="q.Choice1 | unsafe" class="ng-binding"></p><div class="cz-ltr "><span class="rz-entext">go shopping</span></div>
                                                        </div>', '<div id="2291896_view_2">
                                                            <p ng-bind-html="q.Choice2 | unsafe" class="ng-binding"></p><div class="cz-ltr "><span class="rz-entext">play computer games</span></div>
