INSERT INTO questions_temps (id, category_question_id, front, back, p1, p2, p3, p4, answer, percentage, count, type, isfree, created_at, updated_at) VALUES ('1963', '397', '<div class="fullWidth">
                                                        <p ng-bind-html="q.QuestionText | unsafe" class="ng-binding"></p><div><div><span class="rz-text">جاهای خالی زیر به</span><span>‌</span><span class="rz-text">ترتیب با واژگان کدام گزینه تکمیل می</span><span>‌</span><span class="rz-text">گردند؟</span></div><div class="rz-ltr "><span class="rz-entext">A: The weather is .......... in summer and .......... in winter.</span></div><div class="rz-ltr "><span class="rz-entext">B: Things that you like to do in your free time are .......... .</span></div></div>
                                                    </div>', '<div class="QuestionContent p-r-15 rtl ng-hide" ng-show="q.ShowStyle==2 &amp;&amp; q.CurrentImage=='a' &amp;&amp; q.CString==''" aria-hidden="true">
                                            <p ng-bind-html="q.AnswerText | unsafe" class="ng-binding"></p><div><div><span class="az-text">گزینه ۲‏ پاسخ صحیح است. ترجمهٔ جمله</span><span>‌</span><span class="az-text">ها: A‏: هوا در تابستان </span><u><span class="az-text">داغ</span></u><span class="az-text"> و در زمستان </span><u><span class="az-text">سرد</span></u><span class="az-text"> است.</span></div><div><span class="az-text">B‏: کارهایی که شما دوست دارید در اوقات فراغتتان انجام دهید، </span><u><span class="az-text">سرگرمی</span></u><span class="az-text"> هستند.</span></div><div><span class="az-text">۱‏) داغ - گرم - فعالیت</span><span>‌</span><span class="az-text">ها</span><span>                        </span><span class="az-text">۲‏) داغ - سرد - سرگرمی</span><span>‌</span><span class="az-text">ها</span><span>                        </span><span class="az-text">۳‏) گرم - داغ - سرگرمی</span><span>‌</span><span class="az-text">ها</span><span>                        </span><span class="az-text">۴‏) سرد - داغ - فعالیت</span><span>‌</span><span class="az-text">ها</span></div></div>
                                        </div>', '<div id="2285668_view_1">
